import{_ as e,o as t,c as o,a2 as d}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"API de imagem aleatória e galeria pública","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/Other/random-image-api-and-public-gallery.md","filePath":"pt-BR/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),r={name:"pt-BR/Other/random-image-api-and-public-gallery.md"};function i(s,a,c,n,l,p){return t(),o("div",null,[...a[0]||(a[0]=[d(`<h1 id="api-de-imagem-aleatoria-e-galeria-publica" tabindex="-1">API de imagem aleatória e galeria pública <a class="header-anchor" href="#api-de-imagem-aleatoria-e-galeria-publica" aria-label="Permalink to &quot;API de imagem aleatória e galeria pública&quot;">​</a></h1><p>As duas funções são configuradas em:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configurações do sistema -&gt; Outras configurações</span></span></code></pre></div><h2 id="api-de-imagem-aleatoria" tabindex="-1">API de imagem aleatória <a class="header-anchor" href="#api-de-imagem-aleatoria" aria-label="Permalink to &quot;API de imagem aleatória&quot;">​</a></h2><p>A API de imagem aleatória escolhe um arquivo aleatoriamente a partir dos diretórios definidos. Ela serve para fundos de site, rotação de avatar ou chamadas externas de imagens aleatórias.</p><p>Depois de ativada, use:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://seu-dominio/random</span></span></code></pre></div><h2 id="configuracoes-da-api" tabindex="-1">Configurações da API <a class="header-anchor" href="#configuracoes-da-api" aria-label="Permalink to &quot;Configurações da API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opção</th><th>Descrição</th></tr></thead><tbody><tr><td>Habilitar</td><td>Liga ou desliga <code>/random</code>; desligada, a rota nega acesso</td></tr><tr><td>Diretórios</td><td>Limita de quais diretórios os arquivos podem ser escolhidos</td></tr><tr><td>Exemplo de chamada</td><td>Gera um link de API pronto para copiar</td></tr></tbody></table><p>Você pode escolher vários diretórios. Se permitir apenas <code>/landscape/</code> e <code>/portrait/</code>, a API só escolherá arquivos nesses diretórios ou subdiretórios.</p><h2 id="parametros-principais" tabindex="-1">Parâmetros principais <a class="header-anchor" href="#parametros-principais" aria-label="Permalink to &quot;Parâmetros principais&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parâmetro</th><th>Exemplo</th><th>Descrição</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Diretório alvo</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Tipo de mídia: <code>image</code>, <code>video</code>, <code>audio</code> ou combinação por vírgula</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td><code>portrait</code>, <code>landscape</code> ou <code>auto</code></td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Vazio redireciona; <code>url</code> retorna texto; <code>json</code> retorna JSON</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>Com <code>type=url</code>, retorna link completo</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Filtra por classificação etária</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Apenas arquivos com essas tags</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Exclui arquivos com essas tags</td></tr></tbody></table><h2 id="formatos-de-resposta" tabindex="-1">Formatos de resposta <a class="header-anchor" href="#formatos-de-resposta" aria-label="Permalink to &quot;Formatos de resposta&quot;">​</a></h2><p>Sem <code>type</code>, a API redireciona diretamente para o arquivo aleatório.</p><p><code>type=url</code> retorna um link em texto puro.</p><p><code>type=json</code> retorna informações do arquivo: link, ID, nome, tipo, tags, classificação e outros dados.</p><h2 id="restricoes-de-acesso" tabindex="-1">Restrições de acesso <a class="header-anchor" href="#restricoes-de-acesso" aria-label="Permalink to &quot;Restrições de acesso&quot;">​</a></h2><p>A API respeita as regras públicas definidas no painel.</p><table tabindex="0"><thead><tr><th>Regra</th><th>Efeito</th></tr></thead><tbody><tr><td>Limite de diretórios</td><td>Escolhe apenas arquivos em diretórios permitidos</td></tr><tr><td>Lista negra</td><td>Arquivos bloqueados ficam fora do conjunto aleatório</td></tr><tr><td>Modo lista branca</td><td>Retorna apenas arquivos permitidos explicitamente</td></tr><tr><td>Classificação etária</td><td>Filtra R12, R16, R18 conforme o modo de acesso</td></tr></tbody></table><p>Se nenhum arquivo atender aos filtros, a API informa que não há resultado.</p><h2 id="galeria-publica" tabindex="-1">Galeria pública <a class="header-anchor" href="#galeria-publica" aria-label="Permalink to &quot;Galeria pública&quot;">​</a></h2><p>A galeria pública oferece uma página somente leitura para visitantes navegarem pelos diretórios que você permite publicar.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://seu-dominio/browse/nome-do-diretorio</span></span></code></pre></div><h2 id="configuracoes-da-galeria" tabindex="-1">Configurações da galeria <a class="header-anchor" href="#configuracoes-da-galeria" aria-label="Permalink to &quot;Configurações da galeria&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opção</th><th>Descrição</th></tr></thead><tbody><tr><td>Habilitar</td><td>Liga ou desliga a galeria pública</td></tr><tr><td>Modo de carregamento</td><td>Decide se usa arquivo original ou miniatura</td></tr><tr><td>Diretórios públicos</td><td>Define quais diretórios visitantes podem abrir</td></tr></tbody></table><p>Exemplo:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Com essa configuração, visitantes podem acessar:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://seu-dominio/browse/1</span></span>
<span class="line"><span>https://seu-dominio/browse/2</span></span>
<span class="line"><span>https://seu-dominio/browse/landscape</span></span>
<span class="line"><span>https://seu-dominio/browse/portrait</span></span></code></pre></div><p>Diretórios não publicados serão recusados.</p><h2 id="recursos-da-galeria" tabindex="-1">Recursos da galeria <a class="header-anchor" href="#recursos-da-galeria" aria-label="Permalink to &quot;Recursos da galeria&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Recurso</th><th>Descrição</th></tr></thead><tbody><tr><td>Navegar por diretórios</td><td>Ver arquivos e subdiretórios publicados</td></tr><tr><td>Buscar</td><td>Buscar por nome, ID do arquivo ou tag</td></tr><tr><td>Filtrar por tipo</td><td>Imagem, vídeo, áudio ou outros arquivos</td></tr><tr><td>Filtrar por tag</td><td>Incluir ou excluir tags</td></tr><tr><td>Filtrar por orientação</td><td>Horizontal, vertical e outros critérios</td></tr><tr><td>Copiar link</td><td>Copiar o link público do arquivo</td></tr><tr><td>Pré-visualizar mídia</td><td>Ver imagens, vídeos e áudio na página</td></tr></tbody></table>`,32)])])}const m=e(r,[["render",i]]);export{h as __pageData,m as default};
